// Referenciando dados dos nós anteriores
const atrasadasRaw = $('Buscar Tarefas Atrasadas').all();
const hojeRaw = $('Buscar Tarefas de Hoje').all();
const usersRaw = $('Buscar Usuários').first().json;

// Extrair JSONs
const atrasadas = atrasadasRaw.map(i => i.json);
const hoje = hojeRaw.map(i => i.json);
const users = (usersRaw.users || []);

// Mapa de usuários
const userMap = {};
for (const u of users) {
  userMap[u.id] = u.nome;
}

const dataHoje = new Date().toLocaleDateString('pt-BR');

let msg = `📋 BOM DIA! Resumo de tarefas — ${dataHoje}\n\n`;
msg += `⚠️ ${atrasadas.length} tarefa(s) ATRASADA(S)\n`;
msg += `📅 ${hoje.length} tarefa(s) para HOJE\n\n`;

if (atrasadas.length > 0) {
  msg += `🔴 Atrasadas:\n`;
  for (const t of atrasadas) {
    const vencimento = t.data_vencimento
      ? new Date(t.data_vencimento).toLocaleDateString('pt-BR')
      : '?';
    const resp = t.responsavel_id ? (userMap[t.responsavel_id] || '?') : 'Sem responsável';
    msg += `  • ${t.titulo} (venceu ${vencimento}) [${resp}]\n`;
  }
  msg += '\n';
}

if (hoje.length > 0) {
  msg += `📅 Hoje:\n`;
  for (const t of hoje) {
    const resp = t.responsavel_id ? (userMap[t.responsavel_id] || '?') : 'Sem responsável';
    msg += `  • ${t.titulo} [${resp}]${t.descricao ? ' — ' + t.descricao : ''}\n`;
  }
  msg += '\n';
}

if (atrasadas.length === 0 && hoje.length === 0) {
  msg += '✅ Nenhuma tarefa pendente. Dia tranquilo!';
}

return [{
  json: {
    mensagem: msg,
    total_atrasadas: atrasadas.length,
    total_hoje: hoje.length,
    data: dataHoje
  }
}];
